#include <iostream>
#include <string>
#include <sstream>
#include <iomanip>

// Forward declaration of the user's solution entry point.
// We assume the user's 'main' function has been renamed to '_user_main' for testing.
extern int _user_main();

// This function redirects standard input/output to string streams
// and executes the user's solution.
std::string run_user_solution(const std::string& input_str) {
    std::stringstream ss_input(input_str);
    std::stringstream ss_output;

    // Save original cin/cout buffers
    std::streambuf* old_cin_buf = std::cin.rdbuf();
    std::streambuf* old_cout_buf = std::cout.rdbuf();

    // Redirect cin to read from ss_input
    std::cin.rdbuf(ss_input.rdbuf());
    // Redirect cout to write to ss_output
    std::cout.rdbuf(ss_output.rdbuf());

    _user_main(); // Call the user's solution

    // Restore original cin/cout buffers
    std::cin.rdbuf(old_cin_buf);
    std::cout.rdbuf(old_cout_buf);

    return ss_output.str();
}
